SELECT AVG(temp) AS average_temperature
FROM weather_data
WHERE station_id = 1 AND year = 2022;

SELECT COUNT(DISTINCT station_id) AS unique_station_count
FROM weather_data
WHERE data_timestamp LIKE '2023-10-01%';

SELECT AVG(temp) AS average_temperature, COUNT(CASE WHEN rtot > 0 THEN data_id END) AS days_with_precipitation
FROM weather_data
WHERE station_id = 123 AND year = 2022;
